const leads = $input.all();
const cliente = $('Loop Clientes').first().json;
const now = new Date();
const unaSemanaAtras = new Date(now - 7 * 24 * 60 * 60 * 1000);

const parseDate = (dateStr) => {
  if (!dateStr) return null;
  const parts = dateStr.split('/');
  if (parts.length !== 3) return null;
  return new Date(parts[2] + '-' + parts[1] + '-' + parts[0]);
};

const leadsEstaSemana = leads.filter(l => {
  const fecha = parseDate(l.json['Fecha Contacto']);
  return fecha && fecha >= unaSemanaAtras;
});

const total = leads.length;
const estaSemana = leadsEstaSemana.length;
const enviados = leads.filter(l => ['Enviado', 'Seguimiento enviado', 'Interesado', 'Cliente'].includes(l.json['Estado'])).length;
const seguimientos = leads.filter(l => l.json['Estado'] === 'Seguimiento enviado').length;
const interesados = leads.filter(l => l.json['Estado'] === 'Interesado').length;
const clientes_cerrados = leads.filter(l => l.json['Estado'] === 'Cliente').length;

const tasa_respuesta = enviados > 0 ? Math.round((interesados / enviados) * 100) : 0;

return [{
  json: {
    cliente_nombre: cliente.Nombre_Cliente,
    email_cliente: cliente.Email_Cliente,
    plan: cliente.Plan,
    ciudad: cliente.Ciudad,
    total_leads_historico: total,
    contactados_esta_semana: estaSemana,
    total_enviados: enviados,
    total_seguimientos: seguimientos,
    total_interesados: interesados,
    clientes_cerrados: clientes_cerrados,
    tasa_respuesta_pct: tasa_respuesta,
    fecha_reporte: now.toLocaleDateString('es-ES', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' })
  }
}];

